package com.example.rest_kafka_poc.entity;import jakarta.persistence.*;import lombok.AllArgsConstructor;import lombok.Data;import lombok.NoArgsConstructor;@Data@AllArgsConstructor@NoArgsConstructor@Entity@Table(name = "Employee" )public class EmployeeEntity {    @Id    @GeneratedValue(strategy = GenerationType.SEQUENCE)    private int id;    private String firstName;    private String lastName;    private String location;    private int age;    private float salary;}